  ('negroni-gin', 'Perfect Three', null, null, null, 'L’espressione più bilanciata: note pungenti del ginepro, sostenute da una ricca dolcezza vanigliata.', 'The most balanced expression, pungent juniper notes carried by a rich vanilla sweetness.', null, 0),
  ('negroni-gin', 'Contessa', null, null, null, 'Raffinato e setoso, unisce la struttura di un gin tradizionale a sfumature dolci e morbidamente floreali.', 'Refined and silky, blending the frame of a traditional gin with soft, floral, sweet shades.', null, 1),
  ('negroni-gin', 'Austero', null, null, null, 'Imponente e senza compromessi: la gradazione elevata esalta una struttura scura, amara e tostata.', 'Bold and uncompromising, high proof draws out a dark, bitter, toasted structure.', null, 2),
  ('negroni-gin', 'Tropicale', null, null, null, 'Floreale e avvolgente, con sentori botanici esotici che si fondono a una base ricca ma vellutata.', 'Floral and enveloping, with exotic botanicals melting into a rich yet velvety base.', null, 3),
  ('negroni-gin', 'Via della Seta', null, null, null, 'Esotico e speziato, unisce sentori orientali di citronella a un cuore erbaceo artigianale.', 'Exotic and spiced, weaving Eastern lemongrass into an artisanal herbal heart.', null, 4),
  ('negroni-gin', 'Clandestino', null, null, null, 'Un trionfo di erbe e resine artigianali: un sorso profondo e complesso, unico nel suo genere.', 'A triumph of artisanal herbs and resins, deep, complex, one of a kind.', null, 5),
  ('negroni-gin', 'Soprano', null, null, null, 'Verticale e tagliente: il ginepro svetta sull’intensità del bitter e sul rigore del Vermouth dry.', 'Vertical and sharp, juniper rising over bitter intensity and the rigour of dry Vermouth.', null, 6),
  ('negroni-gin', 'Tokyo Zen', null, null, null, 'Limpido e meditativo, un sorso estremamente leggero con un delicato sentore vegetale.', 'Clean and meditative, an exceptionally light sip with a delicate vegetal hint.', null, 7),
  ('negroni-gin', 'Kyoto Flower', null, null, null, 'Delicato e floreale: il fiore di ciliegio fa da protagonista su un sorso rotondo e morbido.', 'Delicate and floral, cherry blossom takes the lead over a round, soft sip.', null, 8),
  ('negroni-gin', 'Boschivo', null, null, null, 'Balsamico e profumato, con sfumature montane che si fondono in un sorso fresco.', 'Balsamic and fragrant, with mountain shades melting into a fresh, clean sip.', null, 9),
  ('negroni-whisky', 'Grand Soir', null, null, null, 'Caldo e legnoso: le note di caramello e rovere del whiskey abbracciano la classica struttura dolce-amara.', 'Warm and woody, caramel and oak from whiskey wrap around the classic bittersweet frame.', null, 0),
  ('negroni-whisky', 'Revolution', null, null, null, 'Oscuro e ribelle: la nota torbata dello scotch si lega al fondo scuro in un sorso profondo e terroso.', 'Dark and rebellious, peated scotch ties into the dark base for a deep, earthy sip.', null, 1),
  ('negroni-whisky', 'Golden Age', null, null, null, 'Morbido e dorato: la rotondità del bourbon si siede su un profilo dolce-amaro limpido e leggero.', 'Soft and golden, the round body of bourbon settles on a clean, light bittersweet profile.', null, 2),
  ('negroni-mezcal', 'Rojo', null, null, null, 'Affumicato e terroso: il carattere rustico dell’agave si sposa con profumi erbacei, ricchi e tradizionali.', 'Smoky and earthy, the rustic character of agave marries rich, traditional herbal aromas.', null, 0),
  ('negroni-mezcal', 'Dorado', null, null, null, 'Fumoso e avvolgente: calde note speziate si fondono a sentori terrosi, un sorso intenso e persistente.', 'Smoky and enveloping, warm spiced notes meet earthy hints in an intense, persistent sip.', null, 1),
  ('negroni-mezcal', 'Bianco', null, null, null, 'Luminoso e vibrante: sfumature erbacee incontrano una spinta minerale, per un sorso fumoso e asciutto.', 'Bright and vibrant, herbal shades meet a mineral push for a smoky, dry sip.', null, 2),
  ('negroni-rum', 'Brisa', null, null, null, 'Trasparente e puro ma sorprendentemente complesso: fresco, floreale, vivace e dissetante.', 'Clear and pure yet surprisingly complex, fresh, floral, lively and thirst-quenching.', null, 0),
  ('negroni-rum', 'Solera', null, null, null, 'Profondo e suadente, dominato da note di melassa, legno tostato e frutta matura: un sorso pieno.', 'Deep and persuasive, led by molasses, toasted wood and ripe fruit, a full-bodied sip.', null, 1),
  ('negroni-rum', 'Siesta', null, null, null, 'Limpido e dorato ma avvolgente e caldo: amabile, meditativo, rilassante e irresistibile.', 'Clear and golden yet warm and enveloping, easy-going, meditative, relaxing, irresistible.', null, 2),
  ('americani-list', 'Opulento', null, null, null, 'Ricco e complesso: spiccano eleganti sentori di vaniglia, spezie e frutta secca che donano rotondità.', 'Rich and complex, elegant notes of vanilla, spice and dried fruit lend roundness.', null, 0),
  ('americani-list', 'Tradizionale', null, null, null, 'Autentico e fortemente legato al territorio piemontese: sprigiona note erbacee, calde e speziate.', 'Authentic and rooted in Piedmont, herbal, warm, spiced notes throughout.', null, 1),
  ('americani-list', 'Balsamico', null, null, null, 'Estremamente aromatico, dominato da sentori di erbe officinali e resine artigianali.', 'Highly aromatic, led by medicinal herbs and artisanal resins.', null, 2),
  ('americani-list', 'Radicale', null, null, null, 'Scuro, intenso e terroso, con spiccate note di china, rabarbaro e un forte retrogusto amaro.', 'Dark, intense and earthy, with pronounced cinchona, rhubarb and a strong bitter finish.', null, 3),
  ('americani-list', 'Ambrato', null, null, null, 'Morbido ed elegante: accarezza il palato con note agrumate e speziate sottili e un finale setoso.', 'Soft and elegant, citrus and subtle spice graze the palate with a silky finish.', null, 4),
  ('americani-list', 'Rosato', null, null, null, 'Fresco, fruttato e amichevole: combina profumi delicati con un tocco di Americano beverino.', 'Fresh, fruity and friendly, delicate aromatics meet an easy-drinking Americano touch.', null, 5),
  ('americani-list', 'Candido', null, null, null, 'Delicato e rinfrescante, si distingue per la limpidezza e per le eleganti sfumature dolci.', 'Delicate and refreshing, clean, with elegantly sweet shades.', null, 6),
  ('americani-list', 'Secco', null, null, null, 'Nitido e affilato: unisce la nota vinosa secca del vermouth dry alle sfumature agrumate e dolci.', 'Crisp and sharp, the dry, wine-like vermouth meets citrus and sweet shades.', null, 7),
  ('americani-list', 'Onesto', null, null, null, 'Diretto e senza compromessi: l’intensità del bitter incontra la finezza del vermouth dry.', 'Direct and uncompromising, bitter intensity meets the finesse of dry vermouth.', null, 8),
  ('americani-list', 'Bianco-cano', null, null, null, 'Inaspettato e dissetante, si bilancia fra vermouth bianco, bitter e la freschezza luppolata della pilsner.', 'Unexpected and refreshing, balanced between white vermouth, bitter and the hoppy lift of pilsner.', null, 9),
  ('americani-list', 'IPA-cano', null, null, null, 'Frizzante, agrumato e luppolato: unisce l’amarezza tipica dell’aperitivo al tocco pungente della birra IPA.', 'Sparkling, citrus-driven and hoppy, classic aperitivo bitterness meets the bite of an IPA.', null, 10),
